import{_ as r,o as a,c as o,a2 as p}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"伯克希尔·哈撒韦 1972 年度股东年报","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1972年/翻译.md","filePath":"01_letters/1972年/翻译.md"}'),n={name:"01_letters/1972年/翻译.md"};function e(s,t,l,i,g,h){return a(),o("div",null,[...t[0]||(t[0]=[p('<h1 id="伯克希尔·哈撒韦-1972-年度股东年报" tabindex="-1">伯克希尔·哈撒韦 1972 年度股东年报 <a class="header-anchor" href="#伯克希尔·哈撒韦-1972-年度股东年报" aria-label="Permalink to &quot;伯克希尔·哈撒韦 1972 年度股东年报&quot;">​</a></h1><p>（截至 1972 年 12 月 30 日，共 52 周）</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p>1–3 董事长致辞</p><p>4 会计师鉴证报告</p><p>财务报表：</p><p>5–10 伯克希尔·哈撒韦公司及合并子公司报表</p><p>未合并子公司报表：</p><p>11–16 保险集团</p><p>17–21 伊利诺伊州罗克福德国民银行与信托公司</p><hr><h2 id="致伯克希尔·哈撒韦公司全体股东" tabindex="-1">致伯克希尔·哈撒韦公司全体股东： <a class="header-anchor" href="#致伯克希尔·哈撒韦公司全体股东" aria-label="Permalink to &quot;致伯克希尔·哈撒韦公司全体股东：&quot;">​</a></h2><p>1972 年，公司营业收益达到期初股东权益的 <strong>19.8%</strong>，表现十分亮眼。所有核心业务板块均实现显著改善，其中<strong>保险承保利润</strong>的增长最为突出。得益于多重利好因素叠加——汽车事故频率下降、事故严重程度缓和、未发生重大灾害，承保利润率达到远高于历史平均与未来预期的水平。</p><p>尽管我们预计 1973 年营业收益会小幅回落，但近年的多元化布局已显著夯实了公司的<strong>常态盈利能力基础</strong>。现任管理层于 1965 年 5 月接手公司，八年后的 1972 年，营业收益达 <strong>11,116,256 美元</strong>，远高于若公司仍将全部资源投入纺织业务所能实现的收益。</p><p>1964 财年末，股东权益总计 <strong>22,138,753 美元</strong>。此后公司未通过现金增发或并购新增股权融资，反而回购股份，使流通股减少 14%。每股账面价值从 1964 年末的 19.46 美元增至 1972 年末的 69.72 美元，<strong>年均复合增长率约 16.8%</strong>。</p><p>近年完成的三笔重大收购，无论从财务还是团队层面都极为成功。三家公司的创始人都是主要出售方，获得了大额现金对价，但仍以不减的热情与创造力继续经营，推动业绩再创新高——他们分别是：杰克·林沃尔特、吉恩·阿贝格、维克·拉布。</p><p>我们将继续寻找现有业务的合理延伸机会，同时发掘新业务，以高效运用资本。</p><h3 id="纺织业务" tabindex="-1">纺织业务 <a class="header-anchor" href="#纺织业务" aria-label="Permalink to &quot;纺织业务&quot;">​</a></h3><p>正如去年年报所预测，1972 年纺织行业出现复苏。近几年，肯·蔡斯与拉尔夫·里格比打造了一支优秀的销售团队，服务与可靠性口碑持续提升；生产能力也完成重组，与销售优势形成互补。</p><p>在行业复苏的助力下，这些努力在 1972 年开始兑现成果：库存得到有效管控，既降低了甩卖损失，也减少了资金占用；产品结构大幅优化。尽管行业整体盈利水平仍是决定纺织业务收益的首要因素，但我们相信，<strong>公司在行业内的相对地位已明显提升</strong>，1973 年前景向好。</p><h3 id="保险承保业务" tabindex="-1">保险承保业务 <a class="header-anchor" href="#保险承保业务" aria-label="Permalink to &quot;保险承保业务&quot;">​</a></h3><p>1972 年，国民赔偿公司传统核心业务的<strong>超高承保利润</strong>带来一个矛盾：它大幅推高了公司全年利润，但也吸引了大量新竞争者以<strong>不具备合理补偿性的费率</strong>进入市场。总体而言，如果今年利润没有如此暴涨，我们未来五年的前景或许会更好。</p><p>去年年报已预判会出现大量新竞争者，1972 年我们也确实经历了保费规模的下滑。我们认为，1973 或 1974 年行业承保利润率将显著收窄，届时市场环境可能恢复到支持我们历史增长节奏的状态。遗憾的是，承保业绩恶化与竞争降温之间存在时滞，在此期间传统业务规模预计仍将同比下滑。</p><p>在杰克·林沃尔特与菲尔·利舍的带领下，经验丰富的管理团队将<strong>坚持以盈利为前提承保</strong>（尽管利润率无法维持 1972 年水平），费率基于长期预期而非短期乐观。这一策略过去虽曾导致规模阶段性下滑，但长期效果优异。</p><p>同样如去年年报所预测，再保险部门 1972 年也面临相似的竞争压力。大量新机构进入这个历来规模不大的领域，费率大幅下调，我们认为此举并不稳健，尤其在巨灾险领域。所幸去年几乎没有重大灾害，我们的承保表现依然良好。</p><p>乔治·杨在短短几年内就将再保险业务打造成<strong>规模可观、持续盈利</strong>的板块。长期来看，我们立志成为再保险领域的主要参与者，但在费率持续恶化的背景下，盲目扩大规模并不明智。我们认为，当前承保风险敞口处于历史高位，一旦潜在损失变为现实，市场将重新定价，届时我们才有机会大幅扩张。</p><p><strong>本土州保险业务</strong>方面，运营最久、规模最大的内布拉斯加意外保险公司（仅在本州展业）实现了良好的承保业绩。运营第二个完整年度，其本土营销模式已得到验证，保费规模达到在该州经营数十年的老牌巨头的约三分之一。</p><p>另外两家在明尼苏达与德州的小型公司，因规模极小，赔付率未达预期。本土州业务管理层明确，<strong>承保盈利是成功的唯一标准</strong>，只有在承保环节做到位后，才能大规模扩张。新公司费用率偏高，这在发展阶段属正常现象。</p><p>约翰·林沃尔特出色地启动了这项业务，并计划 1973 年至少再进入一个州。尽管仍有大量工作要做，但本土州业务已展现出<strong>重大长期潜力</strong>。</p><p>去年我们报告收购了芝加哥家庭与汽车保险公司。当时我们就对这笔收购充满信心，现在更是如此。在维克·拉布的带领下，公司 1972 年延续了优异业绩。1973 年，我们计划以其在库克县大获成功的<strong>城市专项车险模式</strong>，进入佛罗里达（戴德县）与加州（洛杉矶）市场。维克具备管理更大规模业务的能力，预计家庭与汽车保险公司将在几年内显著扩张。</p><h3 id="保险投资业绩" tabindex="-1">保险投资业绩 <a class="header-anchor" href="#保险投资业绩" aria-label="Permalink to &quot;保险投资业绩&quot;">​</a></h3><p>我们非常幸运，1969–1971 年保费规模大幅增长，恰逢利率创下历史高位。大量可投资资金在最佳时点到位，绝大部分配置于<strong>免税债券</strong>。投资收益从 1969 年的 2,025,201 美元增至 1972 年的 6,755,242 美元，且有效税率很低。</p><p>我们的债券组合<strong>赎回保护条款极佳</strong>，当前组合的高平均收益率将在未来多年持续贡献收益。不过，由于当前保费增长停滞，未来几年投资收益的增速将明显放缓。</p><h3 id="银行业务" tabindex="-1">银行业务 <a class="header-anchor" href="#银行业务" aria-label="Permalink to &quot;银行业务&quot;">​</a></h3><p>银行子公司——伊利诺伊州罗克福德国民银行与信托公司，继续保持行业领先的盈利能力。1972 年平均存款税后收益率达 <strong>2.2%</strong>，在以下约束条件下更显卓越：</p><ol><li><p>定期存款占比 60%，以居民储蓄类产品为主，全部按法定最高利率付息；</p></li><li><p>始终保持强劲流动性，不参与货币市场拆借；</p></li><li><p>贷款政策稳健，过去两年净核销率仅为商业银行平均水平的约 5%。</p></li></ol><p>这一业绩直接归功于吉恩·阿贝格与鲍勃·克莱恩的领导，他们经营的银行让股东与储户都能&quot;睡得香、赚得稳&quot;。</p><p>1972 年支付给储户的利息是 1969 年的两倍。我们积极吸收居民定期存款，但并未大力营销大额货币市场存单，尽管过去几年这类资金成本通常更低。</p><p>去年客户贷款增长约 <strong>38%</strong>，这一增幅远高于资产负债表显示的水平——因 1971 年贷款总额包含 1090 万美元短期商业票据，而 1972 年末已不再持有此类票据。</p><p>1972 年，我们&quot;罗克福德领先银行&quot;的地位进一步巩固。但当前利率结构、美联储新收款规则导致可投资资金减少，以及本已不低的地方税可能进一步上调，使得伊利诺伊国民银行 1973 年收益<strong>很难实现增长</strong>。</p><h3 id="财务状况" tabindex="-1">财务状况 <a class="header-anchor" href="#财务状况" aria-label="Permalink to &quot;财务状况&quot;">​</a></h3><p>1973 年 3 月 15 日，伯克希尔以 8% 的利率向 20 家机构贷款人借款 <strong>2000 万美元</strong>，期限至 1993 年 3 月 1 日，1979 年 3 月 1 日起开始偿还本金。其中 900 万美元用于偿还银行贷款，剩余资金投向保险子公司。我们预计未来会有保险业务重大扩张机会，因此提前储备财务资源以抓住机遇。</p><p>银行与保险子公司对客户负有重大受托责任。我们在这些业务中保持<strong>远高于行业标准的资本实力</strong>，同时仍能实现良好的资本回报。我们将继续坚守资本稳健目标，并全力维持盈利水平。</p><p>沃伦·E·巴菲特</p><p>董事会主席</p><p>1973 年 3 月 16 日</p><hr><p><em>完整财务报表详见原始年报</em></p>',48)])])}const _=r(n,[["render",e]]);export{c as __pageData,_ as default};
